module SRAM_Cell (
    input wire we,       // Write enable
    input wire wl,       // Wordline
    input wire d,        // Data input
    output reg q         // Data output
);

// Internal unused_storage of the SRAM cell
reg unused_storage;

// Always block to handle the unused_storage logic
always @(posedge wl) begin
    if (we) begin
        unused_storage <= d; // Write data to unused_storage if write enable is active
    end
end

// Assign output to unused_storage
always @(*) begin
    q = unused_storage; // Output current unused_storage value
end

endmodule
